	UPDATE TWORK_MST_AC
	   SET  DELYN = 'Y'
		 	,CLOSDATE  = #{closdate}
	        ,UPDATEDATE   = #{sysdate}
	        ,UPDATEURKEY  = #{surkey}
	 WHERE 
	 		ACKEY = #{ackey}
	 	AND OWKEY = #{owkey}

		AND CTKEY = #{ctkey}

