/* wms-master-account-sql-oracle.xml  insertTWorkMstAc */
	INSERT INTO TWORK_MST_AC
	(
         CTKEY
        ,OWKEY
        ,ACKEY 
        ,ACTYPE 
        ,ACNAME 
        ,REGNO
		,BUSINESSTYPE
		,BUSINESSCATEGORY 
        ,COUNTRYCODE 
        ,ADDRESS1 
        ,ADDRESS2 
        ,CITY
        ,STATE 
        ,ZIPCODE 
        ,TEL1 
        ,TEL2 
        ,FAX 
        ,CONTACT 
        ,CEO 
        ,UDF1
        ,UDF2
        ,UDF3
        ,REP_ACKEY
        ,REP_ACTYPE
        ,ICGRKEY
        ,ADDRID
        ,EMAIL
        ,REGDATE
        ,CLOSDATE
        ,INSERTDATE 
        ,INSERTURKEY 
        ,UPDATEDATE 
        ,UPDATEURKEY 
        ,DCKEY
        ,DELYN
		,CUST_TYPE
		,CUST_TYPE_DETAIL
	) VALUES (
	     #{ctkey}
	    ,#{owkey}
        ,#{ackey}
        ,#{actype}
        ,#{acname}
        ,#{regno}
        ,#{businesstype}
        ,#{businesscategory}
        ,#{countrycode}
        ,#{address1}
        ,#{address2}
        ,#{city}
        ,#{state}
        ,#{zipcode}
        ,#{tel1}
        ,#{tel2}
        ,#{fax}
        ,#{contact}
        ,#{ceo}
        ,#{udf1}
        ,#{udf2}
        ,#{udf3}
        ,#{repAckey}
        ,#{repActype}
        ,'02'
        ,#{addrid}
        ,#{email}
        ,#{regdate}
        ,#{closdate}
		,#{sysdate}
		,#{surkey}
		,#{sysdate}
		,#{surkey}
        ,#{dckey}
        ,'N'
		,#{custType}
		,#{custTypeDetail}
	)

